import java.io.*;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        try {
            String userInput = "serializedObject"; // User input containing a serialized object

            // Preventing the use of untrusted input streams
            ObjectInputStream in = new ObjectInputStream(new ByteArrayInputStream(userInput.getBytes())) {
                @Override
                protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
                    if (!desc.getName().startsWith("java.lang")) {
                        throw new InvalidClassException("Unauthorized deserialization attempt", desc.getName());
                    }
                    return super.resolveClass(desc);
                }
            };

            Object obj = in.readObject();

            // Perform safe operations with the deserialized object
            if (obj instanceof String) {
                System.out.println((String) obj);
            }

        } catch (IOException | ClassNotFoundException | InvalidClassException e) {
            e.printStackTrace();
        }
    }
}

